import { api } from './client'

export type LeadStage =
  | 'new'
  | 'contacted'
  | 'trial_scheduled'
  | 'trial_done'
  | 'paid'
  | 'active'
  | 'paused'
  | 'churned'

export type LeadSource =
  | 'booking_widget'
  | 'rubitime'
  | 'manual'
  | 'referral'
  | 'ads'
  | 'amocrm'
  | 'other'

export type TouchpointChannel = 'phone' | 'email' | 'sms' | 'telegram' | 'whatsapp' | 'in_person' | 'system'
export type TouchpointDirection = 'inbound' | 'outbound'

export const STAGE_LABELS: Record<LeadStage, string> = {
  new:             'Новый',
  contacted:       'В работе',
  trial_scheduled: 'Записан на пробный',
  trial_done:      'Прошёл пробный',
  paid:            'Оплатил',
  active:          'Учится',
  paused:          'На паузе',
  churned:         'Отвалился',
}

export const STAGES_ORDER: LeadStage[] = ['new', 'contacted', 'trial_scheduled', 'trial_done', 'paid', 'active', 'paused', 'churned']

export interface LeadDto {
  id: string
  source: LeadSource
  sourceMeta: Record<string, unknown>
  stage: LeadStage
  parentName: string | null
  parentPhone: string | null
  parentEmail: string | null
  childName: string | null
  childAge: number | null
  track: string | null
  slotId: string | null
  studentId: string | null
  assignedTo: string | null
  notes: string | null
  lostReason: string | null
  crmUrl: string | null
  createdAt: string
  updatedAt: string
}

export interface TouchpointDto {
  id: string
  leadId: string
  createdBy: string | null
  channel: TouchpointChannel
  direction: TouchpointDirection
  subject: string | null
  body: string | null
  occurredAt: string
  createdAt: string
}

export interface CreateLeadPayload {
  source?: LeadSource
  parentName?: string
  parentPhone?: string
  parentEmail?: string
  childName?: string
  childAge?: number
  track?: string
  notes?: string
  crmUrl?: string
}

export interface CreateTouchpointPayload {
  channel: TouchpointChannel
  direction: TouchpointDirection
  subject?: string
  body?: string
  occurredAt?: string
}

export function fetchLeads(filter: { stage?: LeadStage; assignedTo?: string } = {}): Promise<LeadDto[]> {
  const qs = new URLSearchParams()
  if (filter.stage) qs.set('stage', filter.stage)
  if (filter.assignedTo) qs.set('assignedTo', filter.assignedTo)
  return api.get<LeadDto[]>(`/crm/leads?${qs.toString()}`).catch(() => [])
}

export function fetchStageCounts(): Promise<Record<LeadStage, number>> {
  return api.get<Record<LeadStage, number>>('/crm/leads/counts').catch(() => ({
    new: 0, contacted: 0, trial_scheduled: 0, trial_done: 0,
    paid: 0, active: 0, paused: 0, churned: 0,
  }))
}

export function createLead(payload: CreateLeadPayload): Promise<LeadDto> {
  return api.post<LeadDto>('/crm/leads', payload)
}

export function updateLead(id: string, patch: Partial<CreateLeadPayload>): Promise<LeadDto> {
  return api.patch<LeadDto>(`/crm/leads/${id}`, patch)
}

export function moveLeadStage(id: string, stage: LeadStage, lostReason?: string): Promise<LeadDto> {
  return api.patch<LeadDto>(`/crm/leads/${id}/stage`, { stage, lostReason })
}

export function assignLead(id: string, userId: string): Promise<LeadDto> {
  return api.patch<LeadDto>(`/crm/leads/${id}/assign`, { userId })
}

export function fetchLeadTouchpoints(id: string): Promise<TouchpointDto[]> {
  return api.get<TouchpointDto[]>(`/crm/leads/${id}/touchpoints`)
}

export function addTouchpoint(id: string, payload: CreateTouchpointPayload): Promise<TouchpointDto> {
  return api.post<TouchpointDto>(`/crm/leads/${id}/touchpoints`, payload)
}
